 * @param {number} p
 * @param {number[][]} queries
 * @return {number}
 */
function solve(nums, p, queries) {
    const n = nums.length;
    const MAX_VAL = 50000;

    // Helper function to compute GCD
    const gcd = (a, b) => {
        while (b) {
            [a, b] = [b, a % b];
        }
        return a;
    };

